der/dist/exportHelper.js","src://tavern_helper_template/webpack/bootstrap","src://tavern_helper_template/external var \"Vue\"","src://tavern_helper_template/src/char_info_viewer/services/attributeWarning.ts","src://tavern_helper_template/src/char_info_viewer/services/common.ts","src://tavern_helper_template/src/char_info_viewer/services/yamlParser.ts","src://tavern_helper_template/src/char_info_viewer/services/importService.ts","src://tavern_helper_template/src/char_info_viewer/services/themeService.ts","webpack://tavern_helper_template/./src/char_info_viewer/App.vue?7dd5","src://tavern_helper_template/src/char_info_viewer/services/particleEngine.ts","webpack://tavern_helper_template/src/char_info_viewer/App.vue?5579","src://tavern_helper_template/src/char_info_viewer/index.ts"],"sourcesContent":["\"use strict\";\nObject.defineProperty(exports, \"__esModule\", { value: true });\n// runtime helper for setting properties on components\n// in a tree-shakable way\nexports.default = (sfc, props) => {\n    const target = sfc.__vccOpts || sfc;\n    for (const [key, val] of props) {\n        target[key] = val;\n    }\n    return target;\n};\n","// The module cache\nvar __webpack_module_cache__ = {};\n\n// The require function\nfunction __webpack_require__(moduleId) {\n\t// Check if module is in cache\n\tvar cachedModule = __webpack_module_cache__[moduleId];\n\tif (cachedModule !== undefined) {\n\t\treturn cachedModule.exports;\n\t}\n\t// Create a new module (and put it into the cache)\n\tvar module = __webpack_module_cache__[moduleId] = {\n\t\t// no module.id needed\n\t\t// no module.loaded needed\n\t\texports: {}\n\t};\n\n\t// Execute the module function\n\t__webpack_modules__[moduleId](module, module.exports, __webpack_require__);\n\n\t// Return the exports of the module\n\treturn module.exports;\n}\n\n","const __WEBPACK_NAMESPACE_OBJECT__ = Vue;","/**\n * 从 `charinfo_source/attributeWarningSystem.js` 迁移而来的“属性警示系统”服务。\n *\n * 保留原始判定规则，但改造成 `src/3.0.2` 可直接引用的 TypeScript 模块。\n */\n\nexport const ATTRIBUTE_KEYS = ['力量', '敏捷', '体质', '智力', '精神'] as const;\n\nexport type AttributeKey = (typeof ATTRIBUTE_KEYS)[number];\n\nexport type AttributeFormulaPartWarning = {\n  index: number;\n  text: string;\n  value: number | null;\n  isWarning: boolean;\n};\n\nexport type AttributeWarningState = {\n  total: string;\n  formula: string;\n  isTotalAbnormal: boolean;\n  formulaPartWarnings: AttributeFormulaPartWarning[];\n  hasFormulaWarning: boolean;\n};\n\nexport type AttributeWarningItem = AttributeWarningState & {\n  key: AttributeKey;\n  short: string;\n  rawValue: unknown;\n  totalThirdPartSum: number;\n};\n\nexport const ATTRIBUTE_SHORT_NAMES: Record<AttributeKey, string> = {\n  力量: '力',\n  敏捷: '敏',\n  体质: '体',\n  智力: '智',\n  精神: '精',\n};\n\nexport const ATTRIBUTE_ALIASES: Record<AttributeKey, string[]> = {\n  力量: ['力量'],\n  敏捷: ['敏捷'],\n  体质: ['体质', '體質'],\n  智力: ['智力'],\n  精神: ['精神'],\n};\n\n/**\n * 对应原 `c(e)`：\n * - 支持纯数字：`12`\n * - 支持公式结果：`6+2+1=9`\n */\nexport function parseAttributeTotal(value: unknown): number {\n  if (value == null) return 0;\n\n  const text = String(value).trim();\n\n  if (text.includes('=')) {\n    const parts = text.split('=');\n    const lastPart = parts[parts.length - 1].trim();\n    return parseInt(lastPart, 10) || 0;\n  }\n\n  return parseInt(text, 10) || 0;\n}\n\n/**\n * 对应原 `bt(e)`：拆分公式与最终总值。\n */\nexport function splitAttributeFormula(value: unknown): { total: string; formula: string } {\n  if (value == null) return { total: '0', formula: '' };\n\n  const text = String(value).trim();\n  if (!text) return { total: '0', formula: '' };\n\n  if (!text.includes('=')) {\n    return { total: String(parseAttributeTotal(text)), formula: '' };\n  }\n\n  const parts = text.split('=');\n  const formula = parts.slice(0, -1).join('=').trim();\n  const total = parts[parts.length - 1]?.trim() || String(parseAttributeTotal(text));\n\n  return { total, formula };\n}\n\n/**\n * 对应原 `St(e, t)`：兼容属性键别名读取。\n */\nexport function getAttributeRawValue(\n  attributes: Record<string, unknown> | null | undefined,\n  key: AttributeKey,\n): unknown {\n  const aliases = ATTRIBUTE_ALIASES[key] || [key];\n\n  for (const alias of aliases) {\n    const value = attributes?.[alias];\n    if (value != null) return value;\n  }\n\n  return undefined;\n}\n\n/**\n * 对应原 `lp`：根据角色等级换算“公式第二段”的等级阶梯值。\n */\nexport function getLevelBracket(level: unknown): number {\n  const numericLevel = parseInt(String(level ?? '1'), 10) || 1;\n\n  if (numericLevel >= 25) return 7;\n  if (numericLevel >= 21) return 6;\n  if (numericLevel >= 17) return 5;\n  if (numericLevel >= 13) return 4;\n  if (numericLevel >= 9) return 3;\n  if (numericLevel >= 5) return 2;\n  return 1;\n}\n\n/**\n * 原模板中第二段公式的警示条件为：`part > lp.value - 1`\n */\nexport function getFormulaSecondPartLimit(level: unknown): number {\n  return getLevelBracket(level) - 1;\n}\n\n/**\n * 原模板中第三段公式共用总上限：`zSum > 等级 - 1`\n */\nexport function getFormulaThirdPartLimit(level: unknown): number {\n  const numericLevel = parseInt(String(level ?? '1'), 10) || 1;\n  return numericLevel - 1;\n}\n\n/**\n * 对应原 `zSum`：统计所有属性公式第三段（索引 2）之和。\n */\nexport function getFormulaThirdPartSum(attributes: Record<string, unknown> | null | undefined): number {\n  return Object.values(attributes || {}).reduce<number>((sum, value) => {\n    const parts = String(value).split('=')[0].split('+');\n    if (parts.length >= 3) {\n      return sum + (parseInt(parts[2].trim(), 10) || 0);\n    }\n    return sum;\n  }, 0);\n}\n\n/**\n * 拆分单个属性公式的各段，并给出逐段警示状态。\n *\n * 保持与原模板一致：\n * - 第 1 段（索引 0）> 6 时警示\n * - 第 2 段（索引 1）> `getLevelBracket(level) - 1` 时警示\n * - 第 3 段（索引 2）不看单项值，而看“所有属性第三段总和”是否超过 `等级 - 1`\n */\nexport function getFormulaPartWarnings(\n  formula: string,\n  level: unknown,\n  totalThirdPartSum: number,\n): AttributeFormulaPartWarning[] {\n  if (!formula) return [];\n\n  const secondPartLimit = getFormulaSecondPartLimit(level);\n  const thirdPartLimit = getFormulaThirdPartLimit(level);\n\n  return formula.split('+').map((part, index) => {\n    const trimmed = part.trim();\n    const numericValue = parseInt(trimmed, 10);\n\n    let isWarning = false;\n\n    if (index === 0) {\n      isWarning = numericValue > 6;\n    } else if (index === 1) {\n      isWarning = numericValue > secondPartLimit;\n    } else if (index === 2) {\n      isWarning = totalThirdPartSum > thirdPartLimit;\n    }\n\n    return {\n      index,\n      text: trimmed,\n      value: Number.isNaN(numericValue) ? null : numericValue,\n      isWarning,\n    };\n  });\n}\n\n/**\n * 对单个属性生成完整警示结果。\n *\n * 总值规则来自原 `$t`：\n * - `< 0` 或 `> 20` 即为异常\n */\nexport function getAttributeWarningState(\n  rawValue: unknown,\n  level: unknown,\n  totalThirdPartSum = 0,\n): AttributeWarningState {\n  const parsed = splitAttributeFormula(rawValue);\n  const numericTotal = parseInt(parsed.total, 10);\n  const isTotalAbnormal = Number.isNaN(numericTotal) || numericTotal < 0 || numericTotal > 20;\n  const formulaPartWarnings = getFormulaPartWarnings(parsed.formula, level, totalThirdPartSum);\n\n  return {\n    total: parsed.total,\n    formula: parsed.formula,\n    isTotalAbnormal,\n    formulaPartWarnings,\n    hasFormulaWarning: formulaPartWarnings.some(part => part.isWarning),\n  };\n}\n\n/**\n * 批量生成五维属性警示结果。\n */\nexport function buildAttributeWarningList(\n  attributes: Record<string, unknown> | null | undefined,\n  level: unknown,\n): AttributeWarningItem[] {\n  const totalThirdPartSum = getFormulaThirdPartSum(attributes);\n\n  return ATTRIBUTE_KEYS.map(key => {\n    const rawValue = getAttributeRawValue(attributes, key);\n    const warningState = getAttributeWarningState(rawValue, level, totalThirdPartSum);\n\n    return {\n      key,\n      short: ATTRIBUTE_SHORT_NAMES[key] || key,\n      rawValue,\n      totalThirdPartSum,\n      ...warningState,\n    };\n  });\n}\n\n/**\n * 生成以属性名为键的警示结果，便于按 key 读取。\n */\nexport function buildAttributeWarningMap(\n  attributes: Record<string, unknown> | null | undefined,\n  level: unknown,\n): Record<AttributeKey, AttributeWarningItem> {\n  return Object.fromEntries(buildAttributeWarningList(attributes, level).map(item => [item.key, item])) as Record<\n    AttributeKey,\n    AttributeWarningItem\n  >;\n}\n","export function hasText(val: unknown): boolean {\n  if (!val) return false;\n  const s = normalizeDisplayText(val).toLowerCase();\n  return s !== '' && s !== 'null' && s !== 'none' && s !== '[]';\n}\n\nexport function hasArrayContent(arr: unknown): arr is unknown[] {\n  return Array.isArray(arr) && arr.length > 0;\n}\n\nexport function parseAttributeValue(val: unknown): number {\n  if (val === undefined || val === null) return 0;\n  const str = normalizeDisplayText(val);\n  if (str.includes('=')) {\n    const parts = str.split('=');\n    const lastPart = parts[parts.length - 1].trim();\n    return parseInt(lastPart, 10) || 0;\n  }\n  return parseInt(str, 10) || 0;\n}\n\nexport function normalizeDisplayText(input: unknown): string {\n  let text = String(input ?? '').trim();\n\n  while (text.length >= 2) {\n    const first = text[0];\n    const last = text[text.length - 1];\n    const wrappedByDouble = first === '\"' && last === '\"';\n    const wrappedBySingle = first === \"'\" && last === \"'\";\n    if (!wrappedByDouble && !wrappedBySingle) break;\n\n    const inner = text.slice(1, -1).trim();\n    if (!inner) {\n      text = '';\n      break;\n    }\n\n    text = inner;\n  }\n\n  return text;\n}\n\nfunction splitSmartList(input: string): string[] {\n  const items: string[] = [];\n  let current = '';\n  let inSingleQuote = false;\n  let inDoubleQuote = false;\n\n  const normalizeListItem = (value: string) =>\n    normalizeDisplayText(\n      normalizeDisplayText(value)\n        .replace(/^[\\[(]+|[\\])]$/g, '')\n        .trim(),\n    );\n\n  for (let index = 0; index < input.length; index += 1) {\n    const char = input[index];\n    const prev = index > 0 ? input[index - 1] : '';\n\n    if (char === '\"' && prev !== '\\\\' && !inSingleQuote) {\n      inDoubleQuote = !inDoubleQuote;\n      current += char;\n      continue;\n    }\n\n    if (char === \"'\" && prev !== '\\\\' && !inDoubleQuote) {\n      inSingleQuote = !inSingleQuote;\n      current += char;\n      continue;\n    }\n\n    const isDelimiter = /[,;|，；、]/.test(char);\n    if (isDelimiter && !inSingleQuote && !inDoubleQuote) {\n      const normalized = normalizeListItem(current);\n      if (normalized && normalized.toLowerCase() !== 'null' && normalized.toLowerCase() !== 'none') {\n        items.push(normalized);\n      }\n      current = '';\n      continue;\n    }\n\n    current += char;\n  }\n\n  const normalized = normalizeListItem(current);\n  if (normalized && normalized.toLowerCase() !== 'null' && normalized.toLowerCase() !== 'none') {\n    items.push(normalized);\n  }\n\n  return items;\n}\n\nexport function getSmartArray(input: unknown): string[] {\n  if (input === undefined || input === null) return [];\n  if (Array.isArray(input)) {\n    return input.map(item => normalizeDisplayText(item)).filter(Boolean);\n  }\n\n  const str = String(input).trim();\n  if (!str || str.toLowerCase() === 'null' || str.toLowerCase() === 'none') return [];\n\n  const processed = str.replace(/\\]\\s*\\[/g, '],[').trim();\n  const content = processed.startsWith('[') && processed.endsWith(']') ? processed.slice(1, -1) : processed;\n  return splitSmartList(content);\n}\n\nexport function escapeHtml(str: unknown): string {\n  const div = document.createElement('div');\n  div.textContent = String(str ?? '');\n  return div.innerHTML;\n}\n","import { load } from 'js-yaml';\nimport type { CharacterData, FriendlyYamlError, ParseResult } from '../types';\n\nconst KEY_ALIAS_TO_SIMPLIFIED: Record<string, string> = {\n  名字: '姓名',\n  名稱: '名称',\n  等級: '等级',\n  種族: '种族',\n  生命層級: '生命层级',\n  身分: '身份',\n  職業: '职业',\n  喜愛: '喜爱',\n  外貌特質: '外貌特质',\n  外貌特徵: '外貌特质',\n  外貌特征: '外貌特质',\n  衣物裝飾: '衣物装饰',\n  屬性: '属性',\n  資源: '资源',\n  體質: '体质',\n  裝備: '装备',\n  登神長階: '登神长阶',\n  神國: '神国',\n  權能: '权能',\n  法則: '法则',\n  標籤: '标签',\n  品質: '品质',\n  類型: '类型',\n  分類: '分类',\n  被動效果: '被动效果',\n  主動效果: '主动效果',\n};\n\nfunction visualizeForDisplay(str: unknown): string {\n  return String(str ?? '')\n    .replace(/\\t/g, '⇥')\n    .replace(/\\u00A0/g, '⍽');\n}\n\nfunction normalizeKey(key: string): string {\n  return KEY_ALIAS_TO_SIMPLIFIED[key] || key;\n}\n\nfunction normalizeObjectKeysDeep(input: unknown): unknown {\n  if (Array.isArray(input)) {\n    return input.map(item => normalizeObjectKeysDeep(item));\n  }\n\n  if (!input || typeof input !== 'object') {\n    return input;\n  }\n\n  const source = input as Record<string, unknown>;\n  const output: Record<string, unknown> = {};\n\n  Object.entries(source).forEach(([rawKey, rawValue]) => {\n    const normalizedKey = normalizeKey(String(rawKey));\n    const normalizedValue = normalizeObjectKeysDeep(rawValue);\n\n    if (!(normalizedKey in output) || rawKey === normalizedKey) {\n      output[normalizedKey] = normalizedValue;\n    }\n  });\n\n  return output;\n}\n\nexport function normalizeCharacterDataKeys(data: CharacterData): CharacterData {\n  return normalizeObjectKeysDeep(data) as CharacterData;\n}\n\ntype PreparedYaml = {\n  cleaned: string;\n  source: string;\n  lineOffset: number;\n};\n\nfunction unwrapCharacterInfoWrapper(yamlStr: string): { source: string; lineOffset: number } {\n  const text = String(yamlStr ?? '').trim();\n  const openMatch = text.match(/^<char_info>\\s*/i);\n  const closeMatch = text.match(/\\s*<\\/char_info>$/i);\n\n  if (!openMatch || !closeMatch || openMatch[0].length >= text.length - closeMatch[0].length) {\n    return { source: text, lineOffset: 0 };\n  }\n\n  const source = text.slice(openMatch[0].length, text.length - closeMatch[0].length);\n  const lineOffset = openMatch[0].split('\\n').length - 1;\n  return { source, lineOffset };\n}\n\nfunction prepareYaml(yamlStr: string): PreparedYaml {\n  if (!yamlStr) return { cleaned: '', source: '', lineOffset: 0 };\n\n  const unwrapped = unwrapCharacterInfoWrapper(yamlStr);\n  const normalized = unwrapped.source\n    .replace(/\\u00A0/g, ' ')\n    .replace(/\\t/g, '  ')\n    .replace(/】/g, ']')\n    .replace(/【/g, '[');\n\n  const lines = normalized.split('\\n');\n  const sensitiveKeys = [\n    '身份',\n    '身分',\n    '职业',\n    '職業',\n    '性格',\n    '喜爱',\n    '喜愛',\n    '外貌特质',\n    '外貌特質',\n    '外貌特征',\n    '外貌特徵',\n    '衣物装饰',\n    '衣物裝飾',\n    '背景故事',\n    '描述',\n    '效果',\n    '标签',\n    '標籤',\n    '消耗',\n    '类型',\n    '類型',\n    '品质',\n    '品質',\n    '神位',\n    '名称',\n    '名稱',\n    '姓名',\n    '名字',\n    '种族',\n    '種族',\n    '等级',\n    '等級',\n    '生命层级',\n    '生命層級',\n  ];\n  const attrKeys = ['力量', '敏捷', '体质', '體質', '智力', '精神'];\n\n  const cleanedLines = lines.map(line => {\n    line = line.replace(/^(\\s*)(-\\s*)?([-\\w\\u4e00-\\u9fa5]+)\\s*：/, (_m, indent, dash, key) => {\n      return `${indent}${dash || ''}${key}:`;\n    });\n\n    const match = line.match(/^(\\s*)(-\\s*)?([-\\w\\u4e00-\\u9fa5]+)\\s*:\\s*(.*)$/);\n    if (!match) return line;\n\n    const indent = match[1];\n    const dash = match[2] || '';\n    const key = match[3];\n    let val = match[4].trim();\n\n    if (!val) return line;\n    if (val.startsWith('|') || val.startsWith('>')) return line;\n\n    if (attrKeys.some(k => key.includes(k))) {\n      if ((/[+=]/.test(val) || val.includes('{')) && !/^[\"'].*[\"']$/.test(val)) {\n        val = val.replace(/\"/g, '\\\\\"');\n        return `${indent}${dash}${key}: \"${val}\"`;\n      }\n    }\n\n    const isSensitive = sensitiveKeys.some(k => key.includes(k));\n    const hasDangerousChars = /[{}[\\]]/.test(val);\n    const hasQuoteInside = val.includes('\"');\n    const isFullyQuoted = /^[\"'].*[\"']$/.test(val);\n\n    if ((isSensitive || hasDangerousChars || hasQuoteInside) && !isFullyQuoted) {\n      val = val.replace(/\"/g, '\\\\\"');\n      return `${indent}${dash}${key}: \"${val}\"`;\n    }\n\n    return line;\n  });\n\n  return {\n    cleaned: cleanedLines.join('\\n'),\n    source: unwrapped.source,\n    lineOffset: unwrapped.lineOffset,\n  };\n}\n\nexport function cleanYaml(yamlStr: string): string {\n  return prepareYaml(yamlStr).cleaned;\n}\n\nfunction buildYamlErrorTips(message: string, cleanedLine: string, originalLine: string): string[] {\n  const lowerMessage = message.toLowerCase();\n  const lineText = `${cleanedLine}\\n${originalLine}`;\n\n  if (lowerMessage.includes('bad indentation') || lowerMessage.includes('bad indendation')) {\n    return [\n      '这是缩进问题：同一层级必须使用一样多的空格。',\n      '如果这一行属于列表项内容，通常要比 \"- 名称: xxx\" 多缩进两个空格。',\n      '不要混用 Tab；把行首空白删掉后重新用空格对齐。',\n    ];\n  }\n\n  if (lowerMessage.includes('sequence entry')) {\n    return [\n      '检查这一行附近的 \"- \" 列表符号，列表项必须在同一列对齐。',\n      '列表项下面的字段要缩进到同一层，例如 \"名称/品质/类型/效果\" 的行首空格要一致。',\n      '如果这一行不是新列表项，不要在行首写 \"- \"。',\n    ];\n  }\n\n  if (\n    lowerMessage.includes('document separator') ||\n    lowerMessage.includes('end of the stream') ||\n    lowerMessage.includes('block mapping')\n  ) {\n    return [\n      '通常是上一行或本行缺少冒号，确认格式是 \"键: 值\"。',\n      '如果值里有半角冒号、方括号或引号，把整段值用英文双引号包住。',\n      '如果这是多行文本，键后面写 \"|\"，下一行开始统一多缩进两个空格。',\n    ];\n  }\n\n  if (lowerMessage.includes('duplicated mapping key')) {\n    return [\n      '这一层里出现了重复键名，YAML 不允许同一对象内有两个一样的键。',\n      '如果需要多个技能/装备/道具，请写成列表项，每个条目前面用 \"- 名称: xxx\"。',\n      '如果只是同名效果，建议在效果名前加区分词。',\n    ];\n  }\n\n  if (lowerMessage.includes('unknown escape') || lowerMessage.includes('bad escaped')) {\n    return [\n      '双引号里的反斜杠会被当成转义符；不需要转义时改用单引号。',\n      '如果文本里必须写反斜杠，请写成两个反斜杠。',\n      '也可以把这段改成 \"|\" 多行文本，减少引号转义问题。',\n    ];\n  }\n\n  if (lineText.includes('[') || lineText.includes(']')) {\n    return [\n      '这一行包含方括号；如果解析失败，先把整段值用英文双引号包住。',\n      '标签可以写成 \"[精神][治疗]\"，不要拆成没有逗号的 YAML 数组。',\n      '效果名可以保留方括号，例如 \"微弱要素[圣吻之诺]: 效果内容\"。',\n    ];\n  }\n\n  return [\n    '先看箭头指向的位置，再检查这一行和上一行。',\n    '确认格式是 \"键: 值\"，冒号后面最好留一个空格。',\n    '检查行首空格；同一层级对齐，子内容多缩进两个空格。',\n    '如果内容很长或包含特殊符号，可以改成 \"|\" 多行文本。',\n  ];\n}\n\nfunction buildFriendlyYamlError(\n  err: unknown,\n  originalYaml: string,\n  cleanedYaml: string,\n  lineOffset: number,\n): FriendlyYamlError {\n  const e = err as { reason?: string; message?: string; mark?: { line?: number; column?: number } };\n  const mark = e?.mark;\n  const message = String(e?.reason || e?.message || String(err));\n\n  if (!mark || typeof mark.line !== 'number') {\n    return { message, tips: buildYamlErrorTips(message, '', '') };\n  }\n\n  const line = mark.line;\n  const column = typeof mark.column === 'number' ? mark.column : 0;\n  const originalLineIndex = line + lineOffset;\n\n  const originalLines = String(originalYaml ?? '').split('\\n');\n  const cleanedLines = String(cleanedYaml ?? '').split('\\n');\n\n  const originalLine = originalLines[originalLineIndex] ?? '';\n  const cleanedLine = cleanedLines[line] ?? '';\n\n  const cleanedVisual = visualizeForDisplay(cleanedLine);\n  const originalVisual = visualizeForDisplay(originalLine);\n\n  const caretPad = ' '.repeat(Math.max(0, Math.min(column, cleanedVisual.length)));\n  const caretLine = `${caretPad}^`;\n\n  return {\n    message,\n    line: originalLineIndex,\n    column,\n    cleanedLine: cleanedVisual,\n    originalLine: originalVisual,\n    caretLine,\n    tips: buildYamlErrorTips(message, cleanedVisual, originalVisual),\n  };\n}\n\nexport function parseCharacterYaml(yamlText: string): ParseResult {\n  const prepared = prepareYaml(yamlText);\n  try {\n    const parsedData = load(prepared.cleaned) as CharacterData | null;\n    if (!parsedData) throw new Error('解析结果为空');\n\n    const normalizedData = normalizeCharacterDataKeys(parsedData);\n    return { success: true, data: normalizedData };\n  } catch (err) {\n    return {\n      success: false,\n      error: buildFriendlyYamlError(err, yamlText, prepared.cleaned, prepared.lineOffset),\n    };\n  }\n}\n","import type { CharacterData } from '../types';\nimport { getSmartArray, normalizeDisplayText, parseAttributeValue } from './common';\nimport { normalizeCharacterDataKeys } from './yamlParser';\n\ntype VariableScope = { type: 'message'; message_id: 'latest' };\n\ntype TavernApiLike = {\n  getVariables?: (scope: VariableScope) => Promise<Record<string, any>>;\n  insertOrAssignVariables?: (payload: Record<string, any>, scope: VariableScope) => Promise<void>;\n  getOrCreateChatWorldbook?: (chat: 'current', desiredName: string) => Promise<string>;\n  createWorldbookEntries?: (bookName: string, entries: Array<Record<string, any>>) => Promise<void>;\n  getChatWorldbookName?: (chat: 'current') => Promise<string | null>;\n};\n\nfunction getApi(): TavernApiLike {\n  return ((window as any).TavernHelper || (window.parent as any)?.TavernHelper || window) as TavernApiLike;\n}\n\nfunction ensureString(val: unknown): string {\n  if (Array.isArray(val)) return val.join(', ');\n  return val ? normalizeDisplayText(val) : '';\n}\n\nfunction ensureArray(val: unknown): string[] {\n  return getSmartArray(val);\n}\n\nfunction parseNamedEffectLine(line: string): readonly [string, string] | null {\n  const normalized = normalizeDisplayText(line);\n  if (!normalized) return null;\n\n  const bracketMatch = normalized.match(/^\\[([^\\]]+)\\]\\s*[：:]\\s*(.*)$/);\n  if (bracketMatch) {\n    const key = normalizeDisplayText(bracketMatch[1]);\n    const value = normalizeDisplayText(bracketMatch[2]);\n    if (key && value) return [key, value] as const;\n    return null;\n  }\n\n  const splitIndex = normalized.search(/[：:]/);\n  if (splitIndex <= 0) return null;\n\n  const key = normalizeDisplayText(normalized.slice(0, splitIndex));\n  const value = normalizeDisplayText(normalized.slice(splitIndex + 1));\n  if (!key || !value) return null;\n\n  return [key, value] as const;\n}\n\nfunction parseEffectMap(effectVal: unknown): Record<string, string> {\n  if (effectVal && typeof effectVal === 'object' && !Array.isArray(effectVal)) {\n    const effectObj = effectVal as Record<string, unknown>;\n    return Object.fromEntries(\n      Object.entries(effectObj)\n        .map(([key, value]) => [normalizeDisplayText(key), ensureString(value).trim()] as const)\n        .filter(([key, value]) => key.length > 0 && value.length > 0),\n    );\n  }\n\n  const text = ensureString(effectVal).replace(/\\r\\n/g, '\\n').trim();\n  if (!text) return {};\n\n  const lines = text\n    .split('\\n')\n    .map(line => line.trim())\n    .filter(Boolean);\n\n  const effectMap: Record<string, string> = {};\n  const remains: string[] = [];\n\n  lines.forEach(line => {\n    const named = parseNamedEffectLine(line);\n    if (named) {\n      const [key, value] = named;\n      effectMap[key] = value;\n      return;\n    }\n\n    remains.push(line);\n  });\n\n  if (Object.keys(effectMap).length > 0) {\n    if (remains.length > 0) effectMap.描述 = remains.join('\\n');\n    return effectMap;\n  }\n\n  return { 描述: text };\n}\n\nfunction arrayToMap(\n  arr: unknown,\n  type: 'skill' | 'equip' | 'divinity' | 'backpack',\n): Record<string, Record<string, any>> {\n  const map: Record<string, Record<string, any>> = {};\n  if (!Array.isArray(arr)) return map;\n\n  arr.forEach(item => {\n    if (!item || typeof item !== 'object') return;\n    const anyItem = item as Record<string, any>;\n\n    const itemName = ensureString(anyItem.名称 || anyItem.名稱).trim();\n    if (!itemName) return;\n\n    const { 名称, 名稱, ...rest } = anyItem;\n    const processed: Record<string, any> = { ...rest };\n\n    const tags = processed.标签 ?? processed.標籤;\n    if (tags) processed.标签 = ensureArray(tags);\n    else if (type === 'skill' || type === 'equip' || type === 'backpack') processed.标签 = [];\n    delete processed.標籤;\n\n    if (type !== 'divinity') {\n      processed.效果 = parseEffectMap(processed.效果);\n    }\n\n    if (type === 'equip') {\n      processed.品质 = processed.品质 || processed.品質 || '未知';\n      processed.类型 = processed.分类 || processed.分類 || processed.类型 || processed.類型 || '未知';\n      processed.描述 = processed.描述 || '';\n      processed.位置 = processed.位置 || '';\n    } else if (type === 'skill') {\n      processed.品质 = processed.品质 || processed.品質 || '未知';\n      processed.类型 = processed.类型 || processed.類型 || '未知';\n      processed.消耗 = processed.消耗 ? ensureString(processed.消耗) : '';\n      processed.描述 = processed.描述 || '';\n    } else if (type === 'backpack') {\n      const quantityRaw = processed.数量 ?? processed.數量 ?? processed.持有数量 ?? processed.持有數量 ?? 1;\n      const quantityValue = Number(quantityRaw);\n      processed.品质 = processed.品质 || processed.品質 || '未知';\n      processed.类型 = processed.分类 || processed.分類 || processed.类型 || processed.類型 || '未知';\n      processed.数量 = Number.isFinite(quantityValue) && quantityValue > 0 ? quantityValue : 1;\n      processed.描述 = processed.描述 || '';\n    }\n\n    map[itemName] = processed;\n  });\n\n  return map;\n}\n\nfunction mergeNamedMaps(...maps: Array<Record<string, Record<string, any>>>): Record<string, Record<string, any>> {\n  const merged: Record<string, Record<string, any>> = {};\n\n  maps.forEach(map => {\n    Object.entries(map).forEach(([name, value]) => {\n      const existing = merged[name];\n      if (!existing) {\n        merged[name] = { ...value };\n        return;\n      }\n\n      const existingQty = Number(existing.数量);\n      const nextQty = Number(value.数量);\n      const mergedQty = (Number.isFinite(existingQty) ? existingQty : 0) + (Number.isFinite(nextQty) ? nextQty : 0);\n\n      merged[name] = {\n        ...existing,\n        ...value,\n        标签: Array.from(new Set([...ensureArray(existing.标签), ...ensureArray(value.标签)])),\n        效果: {\n          ...(existing.效果 && typeof existing.效果 === 'object' ? existing.效果 : {}),\n          ...(value.效果 && typeof value.效果 === 'object' ? value.效果 : {}),\n        },\n        数量: mergedQty > 0 ? mergedQty : (value.数量 ?? existing.数量 ?? 1),\n      };\n    });\n  });\n\n  return merged;\n}\n\nfunction statusEffectsToMap(input: unknown): Record<string, Record<string, any>> {\n  const map: Record<string, Record<string, any>> = {};\n\n  const normalizeEffect = (effectName: string, raw: unknown) => {\n    if (!effectName.trim() || !raw || typeof raw !== 'object') return;\n    const effect = raw as Record<string, unknown>;\n    const layerValue = Number(effect.层数 ?? 1);\n    map[effectName] = {\n      类型: ensureString(effect.类型).trim() || '特殊',\n      效果: ensureString(effect.效果).trim(),\n      层数: Number.isFinite(layerValue) && layerValue > 0 ? layerValue : 1,\n      剩余时间: ensureString(effect.剩余时间).trim(),\n      来源: ensureString(effect.来源).trim(),\n    };\n  };\n\n  if (Array.isArray(input)) {\n    input.forEach(item => {\n      if (!item || typeof item !== 'object') return;\n      const anyItem = item as Record<string, unknown>;\n      const effectName = ensureString(anyItem.名称 || anyItem.效果名称 || anyItem.name).trim();\n      normalizeEffect(effectName, anyItem);\n    });\n    return map;\n  }\n\n  if (input && typeof input === 'object') {\n    Object.entries(input as Record<string, unknown>).forEach(([effectName, effectValue]) => {\n      normalizeEffect(effectName, effectValue);\n    });\n  }\n\n  return map;\n}\n\nexport async function importToMvuVariables(data: CharacterData): Promise<void> {\n  const api = getApi();\n  if (typeof api.getVariables !== 'function' || typeof api.insertOrAssignVariables !== 'function') {\n    throw new Error('未检测到 TavernHelper API (getVariables / insertOrAssignVariables)。');\n  }\n\n  const normalizedData = normalizeCharacterDataKeys(data);\n  const charName = normalizedData.姓名 || 'Unknown';\n  const targetScope: VariableScope = { type: 'message', message_id: 'latest' };\n\n  const backpack = mergeNamedMaps(\n    arrayToMap(normalizedData.背包, 'backpack'),\n    arrayToMap(normalizedData.道具, 'backpack'),\n    arrayToMap(normalizedData.物品, 'backpack'),\n    arrayToMap(normalizedData.特殊物品, 'backpack'),\n  );\n\n  const mvuData = {\n    在场: true,\n    生命层级: normalizedData.生命层级 || '第一层级/普通层级',\n    等级: parseInt(String(normalizedData.等级 ?? '1'), 10) || 1,\n    种族: normalizedData.种族 || '未知',\n    身份: ensureArray(normalizedData.身份),\n    职业: ensureArray(normalizedData.职业),\n    性格: ensureString(normalizedData.性格).trim(),\n    喜爱: ensureString(normalizedData.喜爱).trim(),\n    外貌: ensureString(normalizedData.外貌特质).trim(),\n    着装: ensureString(normalizedData.衣物装饰).trim(),\n    属性: {\n      力量: parseAttributeValue(normalizedData.属性?.力量),\n      敏捷: parseAttributeValue(normalizedData.属性?.敏捷),\n      体质: parseAttributeValue(normalizedData.属性?.体质),\n      智力: parseAttributeValue(normalizedData.属性?.智力),\n      精神: parseAttributeValue(normalizedData.属性?.精神),\n    },\n    状态效果: statusEffectsToMap(normalizedData.状态效果),\n    背包: backpack,\n    技能: arrayToMap(normalizedData.技能, 'skill'),\n    装备: arrayToMap(normalizedData.装备, 'equip'),\n    登神长阶: {\n      是否开启: !!(\n        normalizedData.登神长阶 ||\n        (normalizedData.生命层级 && String(normalizedData.生命层级).includes('神'))\n      ),\n      神位: normalizedData.登神长阶?.神位 || normalizedData.神位 || '',\n      神国: {\n        名称: normalizedData.登神长阶?.神国?.名称 || normalizedData.神国?.名称 || '',\n        描述: normalizedData.登神长阶?.神国?.描述 || normalizedData.神国?.描述 || '',\n      },\n      要素: arrayToMap(normalizedData.登神长阶?.要素 || normalizedData.要素, 'divinity'),\n      权能: arrayToMap(normalizedData.登神长阶?.权能 || normalizedData.权能, 'divinity'),\n      法则: arrayToMap(normalizedData.登神长阶?.法则 || normalizedData.法则, 'divinity'),\n    },\n    命定契约: false,\n    好感度: 0,\n    心里话: '',\n    背景故事: normalizedData.背景故事 || '',\n  };\n\n  let currentVars: Record<string, any> | null = null;\n\n  try {\n    currentVars = await api.getVariables(targetScope);\n  } catch {\n    currentVars = null;\n  }\n\n  const keepIfPresent = (val: unknown) => (val === undefined || val === null ? undefined : val);\n  const currentCharacter = currentVars?.stat_data?.关系列表?.[charName];\n\n  const preservedFavor = keepIfPresent(currentCharacter?.好感度);\n  const preservedHeart = keepIfPresent(currentCharacter?.心里话);\n\n  if (preservedFavor !== undefined) (mvuData as any).好感度 = preservedFavor;\n  if (preservedHeart !== undefined) (mvuData as any).心里话 = preservedHeart;\n\n  const updatePayload: Record<string, any> = {\n    stat_data: { 关系列表: { [charName]: mvuData } },\n  };\n\n  await api.insertOrAssignVariables(updatePayload, targetScope);\n}\n\nexport async function saveToChatWorldbook(data: CharacterData, originalYaml: string): Promise<void> {\n  const api = getApi();\n  if (typeof api.getOrCreateChatWorldbook !== 'function' || typeof api.createWorldbookEntries !== 'function') {\n    throw new Error('未检测到 Worldbook API。');\n  }\n\n  const normalizedData = normalizeCharacterDataKeys(data);\n  const characterName = normalizedData.姓名 || 'Unknown';\n  const shortName = characterName.split(/[·\\s]/)[0];\n  const lorebookKey = shortName && shortName.trim().length > 0 ? shortName : characterName;\n\n  let bookName: string | null = null;\n  if (typeof api.getChatWorldbookName === 'function') {\n    bookName = await api.getChatWorldbookName('current');\n  }\n\n  if (!bookName) {\n    const now = new Date();\n    const timeStr = `${now.getFullYear()}_${String(now.getMonth() + 1).padStart(2, '0')}_${String(now.getDate()).padStart(2, '0')}_${now.getHours()}h_${now.getMinutes()}m_${now.getSeconds()}s`;\n    const desiredName = `命定之诗-charinfo-Chat_Book_${timeStr}`;\n    bookName = await api.getOrCreateChatWorldbook('current', desiredName);\n  }\n\n  const newEntry = {\n    name: characterName,\n    enabled: true,\n    strategy: { type: 'selective', keys: [lorebookKey] },\n    position: { type: 'after_character_definition', order: 152 },\n    content: originalYaml,\n  };\n\n  await api.createWorldbookEntries(bookName, [newEntry]);\n}\n","import type { CharacterData, ThemeResolved } from '../types';\n\nexport const raceColorMap: Record<string, string> = {\n  神祗: '#FFFFFF',\n  龙族: '#FFD700',\n  龙姬: '#FFD700',\n  龙裔: '#FFA500',\n  巨龙: '#FFD700',\n  古龙: '#FFD700',\n  亚龙: '#FFAE42',\n  血姬: '#FF0000',\n  血族: '#DC143C',\n  亡灵种族: '#32CD32',\n  不死生物: '#32CD32',\n  翼民: '#00BFFF',\n  翼族: '#00BFFF',\n  堕羽民: '#9370DB',\n  女妖: '#FF1493',\n  人类: '#FFDAB9',\n  矮人: '#D2691E',\n  半身人: '#FFD700',\n  精灵: '#00FF7F',\n  光翅妖精: '#FFFF00',\n  汐海妖精: '#00FFFF',\n  妖精: '#FF00FF',\n  宁芙: '#FF00FF',\n  兽族: '#FF4500',\n  黑角民: '#00CED1',\n  蛇女: '#00FF7F',\n  半人马: '#FF8C00',\n  人鱼: '#00FFFF',\n  地精: '#32CD32',\n  魔物: '#8A2BE2',\n  深渊魔族: '#9400D3',\n  异域生物: '#FF00FF',\n  巨人: '#D2691E',\n  半巨人: '#D2691E',\n  小巨人: '#D2691E',\n  霜巨人: '#00BFFF',\n  泰坦人族: '#FFD700',\n  山妖: '#DAA520',\n  食人魔: '#7CFC00',\n  巨魔: '#7CFC00',\n  雪怪: '#E0FFFF',\n  诗灵: '#EE82EE',\n  英灵: '#00BFFF',\n  从者: '#00BFFF',\n  构装体: '#00CED1',\n  人造生物: '#00FF7F',\n  元素生物: '#FF0000',\n  植物生物: '#00FF00',\n  不定形生物: '#7CFC00',\n  其他: '#E0E0E0',\n};\n\nexport const tierColorMap: Record<number, string> = {\n  1: '#57595D',\n  2: '#50C878',\n  3: '#2196F3',\n  4: '#9932CC',\n  5: '#FFD700',\n  6: '#DC143C',\n  7: '#00FFFF',\n};\n\nconst RACE_ALIAS_TO_SIMPLIFIED: Record<string, string> = {\n  人類: '人类',\n  其它: '其他',\n  詩靈: '诗灵',\n  器靈: '器灵',\n  鑄魂: '铸魂',\n  願靈: '愿灵',\n  聖靈: '圣灵',\n  英靈: '英灵',\n  從者: '从者',\n  構裝: '构装',\n  史萊姆: '史莱姆',\n  異域: '异域',\n  異界: '异界',\n  精靈: '精灵',\n  木靈: '木灵',\n  天舞龍: '天舞龙',\n  魔紋龍: '魔纹龙',\n  亞龍: '亚龙',\n  北境龍裔: '北境龙裔',\n  東方後裔: '东方后裔',\n  花靈: '花灵',\n  人馬: '人马',\n  蠑螈: '蝾螈',\n  墮翼: '堕翼',\n  墮羽: '堕羽',\n  深淵: '深渊',\n  小惡魔: '小恶魔',\n  惡魔: '恶魔',\n  龍: '龙',\n  亞: '亚',\n  靈: '灵',\n  詩: '诗',\n  異: '异',\n  體: '体',\n  構: '构',\n  裝: '装',\n  祇: '祗',\n  魚: '鱼',\n  獸: '兽',\n  種: '种',\n  寧: '宁',\n  墮: '堕',\n  聖: '圣',\n  惡: '恶',\n  從: '从',\n  願: '愿',\n  鑄: '铸',\n  機: '机',\n  鳥: '鸟',\n  馬: '马',\n};\n\nfunction hexToRgbObj(hex: string): { r: number; g: number; b: number } {\n  let h = (hex || '#808080').replace(/^#/, '');\n  if (h.length === 3) h = `${h[0]}${h[0]}${h[1]}${h[1]}${h[2]}${h[2]}`;\n  const r = parseInt(h.substring(0, 2), 16);\n  const g = parseInt(h.substring(2, 4), 16);\n  const b = parseInt(h.substring(4, 6), 16);\n  return {\n    r: Number.isFinite(r) ? r : 128,\n    g: Number.isFinite(g) ? g : 128,\n    b: Number.isFinite(b) ? b : 128,\n  };\n}\n\nfunction rgbToHex(r: number, g: number, b: number): string {\n  const toHex = (v: number) =>\n    Math.max(0, Math.min(255, Math.round(v)))\n      .toString(16)\n      .padStart(2, '0');\n  return `#${toHex(r)}${toHex(g)}${toHex(b)}`;\n}\n\nexport function hexToRgb(hex: string): string {\n  const { r, g, b } = hexToRgbObj(hex);\n  return `${r}, ${g}, ${b}`;\n}\n\nexport function harmonizeAccent(\n  hex: string,\n  mixTarget = '#94a3b8',\n  mixRatio = 0.48,\n  minLuma = 92,\n  maxLuma = 188,\n): string {\n  const base = hexToRgbObj(hex);\n  const target = hexToRgbObj(mixTarget);\n\n  let r = base.r * (1 - mixRatio) + target.r * mixRatio;\n  let g = base.g * (1 - mixRatio) + target.g * mixRatio;\n  let b = base.b * (1 - mixRatio) + target.b * mixRatio;\n\n  const luma = () => 0.299 * r + 0.587 * g + 0.114 * b;\n  let current = luma();\n\n  if (current < minLuma) {\n    const t = (minLuma - current) / 255;\n    r = r + (255 - r) * t;\n    g = g + (255 - g) * t;\n    b = b + (255 - b) * t;\n    current = luma();\n  }\n\n  if (current > maxLuma) {\n    const t = (current - maxLuma) / 255;\n    r = r * (1 - t);\n    g = g * (1 - t);\n    b = b * (1 - t);\n  }\n\n  return rgbToHex(r, g, b);\n}\n\nfunction resolveTier(raw: unknown): number {\n  const tierMap: Record<string, number> = { 一: 1, 二: 2, 三: 3, 四: 4, 五: 5, 六: 6, 七: 7 };\n  const tierText = String(raw || '').trim();\n\n  const tierStr = tierText.match(/第\\s*([一二三四五六七1-7])\\s*[层層][级級]/);\n  if (tierStr) {\n    const token = tierStr[1];\n    return tierMap[token] || parseInt(token, 10) || 1;\n  }\n\n  const directDigit = tierText.match(/[1-7]/);\n  if (directDigit) return parseInt(directDigit[0], 10) || 1;\n\n  const directCn = tierText.match(/[一二三四五六七]/);\n  if (directCn) return tierMap[directCn[0]] || 1;\n\n  return parseInt(tierText, 10) || 1;\n}\n\nfunction normalizeRaceTextForLookup(race: string): string {\n  let normalized = race;\n\n  const aliasEntries = Object.entries(RACE_ALIAS_TO_SIMPLIFIED).sort((a, b) => b[0].length - a[0].length);\n  aliasEntries.forEach(([from, to]) => {\n    if (normalized.includes(from)) {\n      normalized = normalized.split(from).join(to);\n    }\n  });\n\n  return normalized;\n}\n\nfunction resolveRaceKey(race: string): string {\n  const normalizedRace = normalizeRaceTextForLookup(race);\n\n  let raceKey = '其他';\n  for (const k of Object.keys(raceColorMap)) {\n    if (race.includes(k) || normalizedRace.includes(k)) {\n      raceKey = k;\n      break;\n    }\n  }\n  return raceKey;\n}\n\nexport function resolveTheme(data: CharacterData): ThemeResolved {\n  const tier = resolveTier(data.生命层级);\n  const race = data.种族 || '其他';\n  const raceKey = resolveRaceKey(race);\n\n  const raceRawHex = raceColorMap[raceKey] || raceColorMap.其他;\n  const tierRawHex = tierColorMap[tier] || tierColorMap[1];\n\n  const raceHex = harmonizeAccent(raceRawHex, '#808080', 0.1, 84, 198);\n  const tierHex = tierRawHex;\n\n  return {\n    tier,\n    raceKey,\n    raceHex,\n    tierHex,\n    raceRgb: hexToRgb(raceHex),\n    tierRgb: hexToRgb(tierHex),\n  };\n}\n\nexport function applyTheme(theme: ThemeResolved, root: HTMLElement = document.documentElement): void {\n  root.style.setProperty('--race-color', theme.raceHex);\n  root.style.setProperty('--race-color-rgb', theme.raceRgb);\n  root.style.setProperty('--tier-color', theme.tierHex);\n  root.style.setProperty('--tier-color-rgb', theme.tierRgb);\n}\n","import { defineComponent as _defineComponent } from 'vue';\nimport { createElementVNode as _createElementVNode, toDisplayString as _toDisplayString, createTextVNode as _createTextVNode, openBlock as _openBlock, createElementBlock as _createElementBlock, createCommentVNode as _createCommentVNode, renderList as _renderList, Fragment as _Fragment, normalizeClass as _normalizeClass, withModifiers as _withModifiers, createS